import { HttpProblems, ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const tenantId = request.headers.get("x-mock-tenant-id");

  if (!tenantId) {
    return HttpProblems.unauthorized(request, context, {
      detail: "Missing required header: x-mock-tenant-id",
    });
  }

  (request as ZuploRequest & { user?: unknown }).user = {
    sub: "mock-user",
    data: {
      tenantId,
    },
  };

  return request;
}

import { HttpProblems, ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const tenantId = (request as ZuploRequest & { user?: { data?: { tenantId?: string } } })
    .user?.data?.tenantId;

  if (!tenantId) {
    return HttpProblems.badRequest(request, context, {
      detail: "Missing tenantId in request user metadata",
    });
  }

  const upstreamUrl = `https://echo.zuplo.io/${encodeURIComponent(tenantId)}/data`;
  const upstreamRequest = new Request(upstreamUrl, request);

  return fetch(upstreamRequest);
}

